"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[6812],{6812:e=>{e.exports=JSON.parse('{"brand.primary":"李桂香","brand.secondary":"课题组","brand.mailnow":"邮箱","nav.home":"首页","nav.research":"研究","nav.publications":"论文","nav.members":"成员","nav.news":"新闻","nav.contact":"联系","component.footer.labName.primary":"李桂香","component.footer.labName.secondary":"课题组","component.footer.address":"中国南京 东南大学","component.footer.addressdetail":"地址：江苏省南京市江宁区东南大学路2号材料A楼 邮编：211189","component.footer.quickLinks.title":"快速链接","component.footer.quickLinks.about":"关于我们","component.footer.quickLinks.research":"研究方向","component.footer.quickLinks.publications":"发表论文","component.footer.quickLinks.team":"我们团队","component.footer.quickLinks.news":"组内新闻","component.footer.quickLinks.contact":"联系我们","component.footer.popularLinks.title":"常用链接","component.footer.popularLinks.university":"东南大学","component.footer.popularLinks.materials":"材料科学与工程学院","component.footer.popularLinks.master":"东南大学研究生院","component.footer.popularLinks.individual":"材料学院李桂香个人主页","component.footer.popularLinks.QRCode":"欢迎关注课题组微信公众号\\n光电未来智创社","component.footer.wechat.clickToEnlarge":"点击查看大图","component.footer.newsletter.title":"订阅邮件","component.footer.newsletter.placeholder":"请输入邮箱地址","component.footer.newsletter.signup":"订阅","component.footer.copyright.lab":"李桂香课题组","component.footer.copyright.rights":"保留所有权利。","component.footer.copyright.design":"页面设计来源","page.home.carousel.alt.phase":"卤化物钙钛矿相变温度循环","page.home.carousel.alt.member":"新入组成员","page.home.carousel.alt.seu":"东南大学","page.home.carousel.prev":"上一张","page.home.carousel.next":"下一张","page.home.hero.title":"功能光电实验室","page.home.hero.desc":"本课题组聚焦光电功能材料及其器件应用研究。主要方向包括：功能材料的设计与合成、卤化物钙钛矿的制备与光伏应用、新型半导体材料与光电器件开发，以及相关的材料化学与器件物理机理研究。","page.home.hero.cta":"了解更多","page.home.carousel.slide3.title":"学术动态","page.home.carousel.slide3.desc":"学术动态 | Nature Photonics：全界面调控策略构筑高效稳定钙钛矿光伏器件","page.home.carousel.slide3.cta":"查看详情","page.home.profile.alt":"李桂香教授","page.home.profile.name":"李桂香 教授","page.home.profile.title":"教授","page.home.profile.affiliation":"东南大学 \xb7 中国南京","page.home.profile.bio.title":"个人简介","page.home.profile.bio.brief":"李桂香，东南大学青年首席教授、博士生导师，国家级青年人才、欧盟玛丽居里学者。于德国亥姆霍兹材料与能源中心获博士学位，先后在瑞士洛桑联邦理工学院和美国西北大学开展博士后研究。","page.home.profile.bio.more":"展开","page.home.profile.bio.less":"收起","page.home.profile.bio.long_1":"其研究面向功能半导体材料与光电器件，聚焦光伏能量转换中的基础问题与关键技术挑战，涵盖功能分子设计与合成、钙钛矿光伏组件与叠层电池、光伏—储能一体化、新型半导体材料与光电器件开发，以及材料化学与器件物理机理研究，旨在推动新一代功能材料与光电技术的演进及其集成应用。","page.home.profile.bio.long_2":"\\n\\n在国际学术期刊发表论文 80 余篇，近年以第一/通讯作者在 Science、Nature Reviews Materials、Nature Photonics、Nature Energy、Nature Communications、Advanced Materials、Angewandte Chemie 等国际期刊发表论文近 40 篇，多篇入选 ESI 高被引/热点论文，合著英文专著 1 部。担任 Discover Sustainability、Scientific Reports 期刊编委，Journal of Advanced Materials Research创刊编委，并受邀为 Nature Energy、Nature Photonics、Nature Communications、Advanced Materials、JACS 等期刊审稿。主持国家自然科学基金、江苏省基础研究计划及欧盟科技框架计划等项目。入选首批江苏青年科技人才“U35培育”对象，获省部级自然科学二等奖。","page.home.research.aria":"研究方向","page.home.research.title.span":"研究","page.home.research.title.rest":"方向","page.home.research.card1.alt":"钙钛矿太阳能电池设计与制备","page.home.research.card1.title":"功能材料设计与可控制备","page.home.research.card2.alt":"光伏材料与器件","page.home.research.card2.title":"高效光伏材料与器件","page.home.research.card3.alt":"光电物理过程","page.home.research.card3.title":"光电过程与器件物理","page.home.research.card4.alt":"器件稳定性","page.home.research.card4.title":"器件稳定性与系统集成","page.home.research.card5.alt":"信息功能器件","page.home.research.card5.title":"新兴信息功能器件","page.home.research.card6.alt":"数据驱动设计","page.home.research.card6.title":"数据驱动材料与器件设计","page.home.pub.title.span":"精选","page.home.pub.title.rest":"论文","page.home.news.title":"新闻","page.home.news.item1.date":"2026-04-19","page.home.news.item1.title":"春启新程，研聚同心 | 课题组 2026 年春季团建活动圆满落幕","page.home.news.item2.date":"2025-04-15","page.home.news.item2.title":"新闻资讯 | 课题组钙钛矿光伏技术入选首批江苏科技成果清单","page.home.news.item3.date":"2026-03-19","page.home.news.item3.title":"学术动态 | 课题组王少强在《科学通报》期刊发表综述论文","page.home.news.item4.date":"2025-02-26","page.home.news.item4.title":"学术动态 | Nature Energy：课题组合作报道钙钛矿器件光循环稳定性研究","page.home.news.item5.date":"2026-01-28","page.home.news.item5.title":"暖冬聚首，研路相伴 | 课题组新春轰趴团建圆满落幕","page.home.news.item6.date":"2026-01-11","page.home.news.item6.title":"学术动态 | Nature Communications：抗聚集自组装单分子层实现高性能、可扩展的钙钛矿太阳能电池","page.home.common.readMore":"查看更多","page.research.title":"研究方向","page.research.intro_card.title":"总体研究方向","page.research.intro_card.text":"课题组聚焦新型半导体功能材料与光电器件，围绕光电能量转换与信息功能中的关键科学问题，开展从材料设计、器件物理到系统集成与智能优化的系统性研究。","page.research.intro_card.alt":"总体研究方向","page.research.energy_opt_card.title":"能源光电材料与器件（Energy Optoelectronics）","page.research.energy_opt_card.text":"聚焦能源光电转换核心科学问题，从材料设计、器件制备到物理机制开展全链条研究，重点突破钙钛矿光伏、叠层电池等关键技术瓶颈。","page.research.energy_opt_card.alt":"能源光电材料与器件","page.research.cards.1.alt":"钙钛矿太阳能电池","page.research.cards.1.title":"功能材料设计与可控制备","page.research.cards.1.text":"半导体功能材料的分子/晶体结构设计；钙钛矿及相关材料的可控制备与多尺度调控；材料结构-性能关系及优化策略。","page.research.cards.2.alt":"钙钛矿光伏","page.research.cards.2.title":"高效光伏材料与器件","page.research.cards.2.text":"钙钛矿光伏技术与叠层太阳电池；大面积器件与光伏模组制备；光伏材料的环境可持续性与绿色制备。","page.research.cards.3.alt":"新型光电材料","page.research.cards.3.title":"光电过程与器件物理","page.research.cards.3.text":"光电转换中的反应动力学与结晶调控；载流子输运行为与界面/缺陷物理；光电过程调控与器件性能提升机制。","page.research.func_semi_card.title":"功能半导体与智能器件（Functional & Intelligent Semiconductors）","page.research.func_semi_card.text":"围绕器件稳定性、信息功能、智能设计开展研究，实现能源-信息融合的新型器件体系突破。","page.research.func_semi_card.alt":"功能半导体与智能器件","page.research.cards.4.alt":"器件稳定性","page.research.cards.4.title":"器件稳定性与系统集成","page.research.cards.4.text":"能源器件失效机制与长期稳定性；器件封装与环境适应性；光伏-储能系统与集成应用。","page.research.cards.5.alt":"信息功能器件","page.research.cards.5.title":"新兴信息功能器件","page.research.cards.5.text":"信息存储与加密（防伪）；杂化半导体晶体管与多功能光电器件；能源-信息融合的新型器件体系。","page.research.cards.6.alt":"数据驱动设计","page.research.cards.6.title":"数据驱动材料与器件设计","page.research.cards.6.text":"人工智能辅助材料设计与筛选；数据驱动器件结构优化与性能预测；智能光电器件与系统。","page.publications.title":"论文成果","page.publications.selectedTitle":"精选论文","page.publications.seeFull":"完整论文列表见","page.publications.googleScholar":"Google Scholar","page.publications.readMore":"查看原文","page.publications.allAria":"主要论文","page.publications.allTitle":"主要论文","page.publications.before2022":"2022及之前","page.members.title":"成员","page.members.group.prof":"教授","page.members.group.visitingscholar":"访问学者","page.members.group.postdoc":"博士后","page.members.group.phd":"博士研究生","page.members.group.ra":"科研助理","page.members.group.master":"硕士研究生","page.members.group.undergrad":"本科生","page.members.group.alumni":"已毕业","page.members.detail.notFound":"未找到该成员","page.members.detail.backTip":"请返回成员列表。","page.members.detail.backMembers":"返回成员列表","page.members.detail.background":"教育经历","page.members.detail.hobbies":"兴趣爱好","page.members.detail.statement":"个人陈述","page.members.detail.motto":"座右铭","page.members.detail.research":"研究方向","page.members.detail.prof.alt":"李桂香","page.members.detail.prof.title":"李桂香 教授","page.members.detail.prof.role":"教授","page.members.detail.prof.affiliation":"东南大学（中国\xb7南京）","page.members.detail.prof.bio.title":"简介","page.members.detail.prof.bio.p1":"李桂香，东南大学青年首席教授、博士生导师，国家级青年人才、欧盟玛丽\xb7居里学者。于德国亥姆霍兹材料与能源研究中心获得博士学位，先后在洛桑联邦理工学院（EPFL）与西北大学（Northwestern University）从事博士后研究。","page.members.detail.prof.bio.p2":"主要研究方向为功能半导体材料与光电器件，围绕光伏转换中的基础科学问题与关键工程技术展开，包括功能分子设计与合成、钙钛矿太阳能电池组件与叠层电池、光伏—储能一体化、 新型半导体材料与光电器件研发，以及材料化学与器件物理机理研究。","page.members.detail.prof.bio.p3":"在国际学术期刊发表论文 70 余篇，近年以第一/通讯作者在 Science、Nature Reviews Materials、Nature Photonics、Advanced Materials、Angewandte Chemie 等国际期刊发表论文 30 余篇，多篇入选 ESI 高被引/热点论文，合著英文专著 1 部。担任 Discover Sustainability、Scientific Reports 期刊编委，并受邀为 Nature Energy、Nature Communications、Advanced Materials、JACS 等期刊审稿。主持国家自然科学基金高层次青年项目、青年项目及欧盟科技框架计划项目等。入选首批江苏省“U35培养”青年科技人才，获省部级自然科学二等奖。","page.members.detail.prof.back":"← 返回成员列表","page.contact.title":"联系方式","page.contact.intro":"课题组致力于为学生提供一个和谐、温暖、积极向上的科研与学习环境。对于在科研中表现突出的同学，将给予相应奖励。课题组每年计划招收2名博士，4名硕士，以及若干科研助理，欢迎材料、物理、化学或光电子学相关背景的本科、硕士/博士研究生报考、及交流生、博士后、青年学者的加入！","page.contact.requirements.title":"招生要求：","page.contact.requirements.item1":"勤奋踏实，具有较强的科研兴趣、进取心与团队合作精神。","page.contact.requirements.item2":"能够认真遵循导师的科研指导，积极完成各项科研任务。","page.contact.requirements.item3":"具备大学英语四级（CET-4）及以上水平，六级（CET-6）优先。","page.contact.email.intro":"有意向的同学请将个人简历发送至：","page.contact.email.suffix":"（联系人：李桂香教授）。","page.contact.position.title":"工作单位","page.contact.position.value":"东南大学","page.contact.mail.title":"联系邮箱","page.contact.mail.value":"guixiang.li@seu.edu.cn","page.news.title":"新闻动态","page.news.readMore":"阅读更多","page.news.coverAlt":"新闻配图","page.news.empty":"暂无新闻，敬请期待。","page.news.back":"← 返回新闻","page.news.member-report-in.title":"如约而至，共启新篇","page.news.member-report-in.coverAlt":"新成员报到","page.news.member-report-in.p1":"当第一缕晨光穿过实验楼的窗棂落在翻页的记录本上；当走廊尽头传来轻声讨论，思想的火花在空气中悄然碰撞。九月的风，吹散了枝头残留的夏热，更拨动着一颗颗跃动不息的科研脉搏。在这片尚待耕耘的学术沃土上，功能半导体与光电子学研究组的航船，此刻正鸣笛出港！","page.news.20251028-zxc-afm.title":"祝贺课题组张晓春在《Advanced Functional Materials》期刊发表综述——钙钛矿电池缺陷自愈研究进展.","page.news.20251028-zxc-afm.coverAlt":"theme","page.news.20251028-zxc-afm.p1":"近日，东南大学材料学院李桂香教授团队在国际著名期刊《Advanced Functional Materials》上发表题为“Defect-Healing in Perovskite Photovoltaics Driving Long-Term Reliability and Performance”的综述论文。","page.news.20251028-zxc-afm.p2":"该论文系统剖析了钙钛矿太阳能电池（PSCs）的降解机制与缺陷自愈原理，提出四大核心自愈策略，为解决钙钛矿器件稳定性瓶颈、推动其大规模商业化应用提供了关键理论支撑与技术参考。","page.news.20251028-zxc-afm.p18":"东南大学材料学院为该论文的第一单位，课题组科研助理张晓春为论文的第一作者，东南大学李桂香教授、河南大学李萌教授及美国圣母大学曹青博士为通讯作者。","page.news.20251028-zxc-afm.p3":"01 研究背景","page.news.20251028-zxc-afm.p4":"面对全球能源危机与碳中和时代的挑战，高效稳定的光伏技术成为实现绿色能源转型的关键方向。当前，单结钙钛矿太阳能电池的光电转换效率已突破27%，展现出巨大的应用潜力。然而，其商业化进程仍受限于材料固有的不稳定性及对外界环境应力的高度敏感。光照、湿气、热应力和机械疲劳等因素常导致器件性能衰退，成为制约其发展的主要障碍。为此，自修复策略（Defect-Healing）作为一种前沿解决方案应运而生，通过在运行过程中主动修复缺陷，显著延长器件寿命并提升其长期可靠性。","page.news.20251028-zxc-afm.p5":"在此背景下，团队对钙钛矿器件的降解机制与自愈技术进行了系统性总结与深入剖析，揭示缺陷修复的基本机制，并对多种典型自愈方法进行了归纳与比较，为实现钙钛矿光伏器件的长期稳定运行提供了新思路。","page.news.20251028-zxc-afm.p6":"02 研究内容与亮点","page.news.20251028-zxc-afm.p7":"本论文从材料降解与缺陷修复两个层面出发，深入探讨了钙钛矿体系的自愈机理及其工程实现途径，主要亮点如下：","page.news.20251028-zxc-afm.p8":"1. 系统解析外部环境影响机制：全面剖析光诱导效应、热应力、湿气侵蚀及离子迁移等因素对钙钛矿稳定性的影响，揭示了性能衰减的核心机理。","page.news.20251028-zxc-afm.p9":"2. 提出四大核心自愈策略：从组分工程优化、添加剂功能化、动态自修复机制以及应用拓展四个维度，系统总结了代表性研究进展与原理。","page.news.20251028-zxc-afm.p10":"3. 指明未来发展方向：强调多触发响应型自修复体系的设计与系统性集成，提出预测性材料设计和可扩展制备的重要性，为实现从实验室到工业化的转化提供思路。","page.news.20251028-zxc-afm.p11":"该综述为钙钛矿电池的长期可靠性研究提供了系统的理论框架与技术路径，促进了高效稳定光伏器件的发展。相关成果不仅推动了钙钛矿材料科学的深入探索，也为可再生能源技术的可持续发展提供了新思路。","page.news.20251028-zxc-afm.p12":"03 论文信息","page.news.20251028-zxc-afm.p13":"论文题目：Defect-Healing in Perovskite Photovoltaics Driving Long-Term Reliability and Performance","page.news.20251028-zxc-afm.p14":"发表期刊：Advanced Functional Materials","page.news.20251028-zxc-afm.p15":"第一作者：张晓春（科研助理，东南大学材料学院）","page.news.20251028-zxc-afm.p16":"通讯作者：李桂香教授（东南大学）、李萌教授（河南大学）、曹青博士（美国圣母大学）","page.news.20251028-zxc-afm.p17":"论文链接：","page.news.20251111-lgx-np.title":"学术动态 | Nature Photonics：全界面调控策略构筑高效稳定钙钛矿光伏器件","page.news.20251111-lgx-np.coverAlt":"theme","page.news.20251111-lgx-np.coverAlt_1":"Fig.1","page.news.20251111-lgx-np.coverAlt_2":"Fig.2","page.news.20251111-lgx-np.coverAlt_3":"Fig.3","page.news.20251111-lgx-np.coverAlt_4":"Fig.4","page.news.20251111-lgx-np.p1":"近日，东南大学材料学院李桂香教授团队在新兴光伏技术领域取得重大突破。相关研究成果以“Stabilizing high-efficiency perovskite solar cells via strategic interfacial contact engineering”为题，发表于国际顶级学术期刊《Nature Photonics》。","page.news.20251111-lgx-np.p2":"该研究针对钙钛矿太阳能电池产业化进程中长期存在的稳定性瓶颈，提出了一种创新的全界面调控策略，为开发高效、长寿命的杂化半导体光伏器件提供了全新的解决方案。","page.news.20251111-lgx-np.p3":"东南大学材料学院为该论文的第一单位和通讯单位。东南大学李桂香教授、河南大学李萌教授、厦门大学王露遥副教授、伦敦玛丽女王大学李哲教授以及亥姆霍兹材料与能源中心Antonio Abate教授为论文通讯作者；李桂香教授、张祖宏博士研究生、Benjamin Agyei-Tuffour副教授及吴录艳博士为论文第一作者。研究工作得到了东南大学材料学院及相关科研平台的大力支持，并受到多项科研项目的资助。","page.news.20251111-lgx-np.p4":"01 \xa0研究背景","page.news.20251111-lgx-np.p5":"金属卤化物钙钛矿太阳能电池因其优异的光电性能和易量产制造优势，被视为极具前景的新一代光伏技术。","page.news.20251111-lgx-np.p6":"然而，器件在温度、湿度及光照等多重外场作用下的热力学与动力学稳定性不足，尤其是界面缺陷导致的性能快速衰减，严重制约了其商业化进程。","page.news.20251111-lgx-np.p7":"02 \xa0研究内容与亮点","page.news.20251111-lgx-np.p8":"针对上述挑战，李桂香教授团队长期聚焦新型光伏器件界面物理机制与稳定性研究，并在本次工作中创新性地构建了“光活性层表面-接触界面-电子传输层”一体化调控体系。该设计实现了三重提升：","page.news.20251111-lgx-np.p9":"1.显著提高钙钛矿表面的缺陷形成能，从根源上增强了材料结构稳定性；","page.news.20251111-lgx-np.p10":"2.形成界面偶极矩优化能级结构，大幅提升了电荷抽取与传输效率；","page.news.20251111-lgx-np.p11":"3.促进电子传输材料形成致密均匀膜层，有效抑制了离子迁移与电极腐蚀。","page.news.20251111-lgx-np.p12":"经全界面调控，团队成功制备出光电转换效率高达27%（第三方认证26.96%）的钙钛矿光伏器件。在稳定性方面，器件展现出优异的耐久性：在连续光照1200小时后性能几乎无衰减；在85\xb0C高温老化和–40\xb0C至+85\xb0C温度循环测试中，均保持优异的结构完整性与性能输出。这一成果为从根本上解决钙钛矿太阳能电池的工况稳定性难题提供了切实有效的技术路径。","page.news.20251111-lgx-np.p13":"图1：钙钛矿表面结构与性质","page.news.20251111-lgx-np.p14":"图2：钙钛矿与电子传输层之间的光电特性","page.news.20251111-lgx-np.p15":"图3：钙钛矿太阳能电池中的电子提取与器件性能","page.news.20251111-lgx-np.p16":"图4：器件的光伏性能与稳定化机制","page.news.20251111-lgx-np.p17":"03 \xa0论文信息","page.news.20251111-lgx-np.p18":"论文题目：Stabilizing high-efficiency perovskite solar cells via strategic interfacial contact engineering","page.news.20251111-lgx-np.p19":"发表期刊：Nature Photonics","page.news.20251111-lgx-np.p20":"第一作者：李桂香教授、张祖宏博士研究生、Benjamin Agyei-Tuffour副教授、吴录艳博士","page.news.20251111-lgx-np.p21":"通讯作者：李桂香教授（东南大学）、王露遥副教授（厦门大学）、李哲教授（伦敦玛丽女王大学）、李萌教授（河南大学）以及Antonio Abate教授（亥姆霍兹材料与能源中心）","page.news.20251111-lgx-np.p22":"论文链接：","page.news.20260111-lgx-nc.title":"学术动态 | Nature Communications：抗聚集自组装单分子层实现高性能、可扩展的钙钛矿太阳能电池","page.news.20260111-lgx-nc.coverAlt":"theme","page.news.20260111-lgx-nc.coverAlt_1":"Fig.1","page.news.20260111-lgx-nc.coverAlt_2":"Fig.2","page.news.20260111-lgx-nc.coverAlt_3":"Fig.3","page.news.20260111-lgx-nc.coverAlt_4":"Fig.4","page.news.20260111-lgx-nc.p1":"近日，东南大学材料学院李桂香教授及合作团队在钙钛矿太阳能电池空穴传输层的设计与调控方面取得研究进展。相关研究成果以“Anti-aggregation self-assembled monolayers enable high-performance and scalable perovskite solar cells”为题，发表于国际权威期刊《Nature Communications》。","page.news.20260111-lgx-nc.p2":"该研究直面钙钛矿太阳能电池中长期存在的界面缺陷与分子聚集难题，提出了一种基于表面活性剂辅助的“抗聚集自组装单分子层”策略。这一方法为制备高效、稳定、可扩展的钙钛矿太阳能电池提供了新的技术路径。","page.news.20260111-lgx-nc.p3":"东南大学材料学院为该论文的共同通讯单位。东南大学李桂香教授、扬州大学丁建宁教授、李绿洲教授、王爱丽副教授及瑞士洛桑联邦理工学院Mohammad Khaja Nazeeruddin教授为论文通讯作者。研究工作得到了东南大学材料学院及相关科研平台的支持，并获得国家和省部级科研项目的资助。","page.news.20260111-lgx-nc.p4":"01 \xa0研究背景","page.news.20260111-lgx-nc.p5":"钙钛矿太阳能电池因其高光吸收系数、可调节带隙和低成本制备等优势，被视为下一代光伏技术的有力竞争者。其中，p-i-n结构器件效率已突破26%，其关键之一在于使用自组装单分子层（SAMs）来降低界面能量损失。","page.news.20260111-lgx-nc.p6":"然而，SAMs分子在沉积过程中易发生聚集，形成不连续的覆盖层，导致界面缺陷增多、电荷传输受阻，进而影响器件性能和长期稳定性。如何在不牺牲效率的前提下实现SAMs的均匀分散与牢固锚定，成为该领域的研究难点。","page.news.20260111-lgx-nc.p7":"02 \xa0研究内容与亮点","page.news.20260111-lgx-nc.p8":"针对上述问题，研究团队创新性地引入阳离子表面活性剂CTAB（十六烷基三甲基溴化铵），将其与常用的SAM分子——2PACz相结合，通过非键合相互作用抑制2PACz的聚集倾向。","page.news.20260111-lgx-nc.p9":"分子层面的“精准调控”","page.news.20260111-lgx-nc.p10":"理论模拟与实验表明，CTAB中带正电的氮原子与2PACz中电负性的P=O基团发生静电相互作用，显著增强了SAM分子在导电衬底上的吸附与铺展能力，形成覆盖率高、分布均匀的单分子层。","page.news.20260111-lgx-nc.p11":"钙钛矿薄膜质量显著提升","page.news.20260111-lgx-nc.p12":"得益于更均匀的SAM层，钙钛矿薄膜结晶质量明显改善：晶粒尺寸增大、晶界缺陷减少、表面粗糙度降低。这些结构优势有效抑制了非辐射复合，提升了载流子提取效率。","page.news.20260111-lgx-nc.p13":"器件效率与稳定性双突破","page.news.20260111-lgx-nc.p14":"高效率：小面积电池（0.072 cm\xb2）实现26.2% 的功率转换效率，填充因子高达86.45%。","page.news.20260111-lgx-nc.p15":"可扩展性：大面积组件（22.96 cm\xb2）效率达到22.34%，展现出良好的规模化制备潜力。","page.news.20260111-lgx-nc.p16":"高稳定性：封装器件在最大功率点追踪800小时后仍保持80%以上初始效率；在65\xb0C氮气环境中老化1000小时后，效率保持率超过90%。","page.news.20260111-lgx-nc.p17":"该研究不仅提供了一种简单有效的SAM分散策略，更从分子相互作用的角度揭示了界面调控的机制，为高效稳定钙钛矿太阳能电池的设计与制备提供了新范式。尤其是在大面积组件中仍能保持较高效率，显示出该技术具备良好的产业化应用前景。","page.news.20260111-lgx-nc.p18":"图1：分子的理论模拟与实验表征","page.news.20260111-lgx-nc.p19":"图2：基于自组装单分子层的钙钛矿薄膜表征","page.news.20260111-lgx-nc.p20":"图3：基于自组装单分子层的钙钛矿薄膜光学表征","page.news.20260111-lgx-nc.p21":"图4：光伏器件的性能与稳定性","page.news.20260111-lgx-nc.p22":"03 \xa0论文信息","page.news.20260111-lgx-nc.p23":"论文题目：Anti-aggregation self-assembled monolayers enable high-performance and scalable perovskite solar cells","page.news.20260111-lgx-nc.p24":"发表期刊：Nature Communications","page.news.20260111-lgx-nc.p25":"通讯作者：丁建宁教授（扬州大学）、李桂香教授（东南大学）、Mohammad Khaja Nazeeruddin教授（瑞士洛桑联邦理工学院）、李绿洲教授（扬州大学）以及王爱丽副教授（扬州大学）","page.news.20260111-lgx-nc.p26":"论文链接：","page.news.20260128-spring-team-building.title":"暖冬聚首，研路相伴——课题组新春轰趴团建圆满落幕","page.news.20260128-spring-team-building.p1":"岁启新章，春满人间。为迎接癸卯新春的到来，缓解科研工作的紧张节奏，增进课题组师生间的情谊与凝聚力，课题组于1月28日组织了一场别开生面的新春团建轰趴活动，在欢声笑语中共度美好时光。","page.news.20260128-spring-team-building.p2":"活动选址在温馨又充满趣味的轰趴馆，提前布置的新春装饰让现场年味十足：红彤彤的灯笼、喜庆的春联、精致的福字贴满各个角落，刚踏入场地，浓浓的节日氛围便扑面而来。本次团建摒弃了传统的座谈形式，设置了丰富多样的趣味环节，让大家在轻松的氛围中放松身心、增进交流。","page.news.20260128-spring-team-building.p3":"烟火气里见温情，分工协作显同心。活动伊始，师生们便自发分工、默契配合：有人细心择洗时蔬，将新鲜的青菜、菌菇打理得整整齐齐；有人认真摆放肉类、丸子等火锅食材，调试烤炉与火锅的火候；还有人兴致勃勃地尝试调制饮品，将奶与气泡水、果汁巧妙搭配，偶尔的小尝试、小交流，让备餐的时光满是欢声笑语。指尖的忙碌，耳边的闲谈，悄然消融了平日科研中的紧张，让彼此的距离更近一步。","page.news.20260128-spring-team-building.p4":"火锅沸腾暖人心，烤肉飘香聚情谊！","page.news.20260128-spring-team-building.p5":"待食材备好，咕嘟咕嘟的火锅冒着热气，滋滋作响的烤肉散发着诱人香气，师生们围坐在一起，一边涮煮着新鲜食材，一边翻动着烤盘里的肉串，偶尔举杯品尝自制的饮品，畅谈科研中的小趣事、生活里的小美好。","page.news.20260128-spring-team-building.p6":"美食治愈心灵，欢聚不负时光。酒足饭饱后，大家围坐在一起，开启了轻松有趣的狼人杀游戏。没有科研数据的严谨，没有论文写作的繁琐，只有纯粹的欢乐与默契：有人化身“狼人”，巧妙伪装、暗藏锋芒；有人担任“预言家”，沉着分析、指引方向；有人身为“平民”，认真倾听、谨慎判断，偶尔的失误与脑洞大开的发言，引得全场捧腹大笑。游戏间隙，课题组负责人李桂香教授与大家亲切谈心，回顾了过去一年课题组的并肩奋斗与收获，感谢每一位成员的辛勤付出与默默坚守，并送上了新春的美好祝福，叮嘱大家新的一年既要潜心科研，也要好好生活，愿大家在温暖的集体中，不负韶华、共赴新程。","page.news.20260128-spring-team-building.p7":"夜幕渐深，欢声笑语依旧未停，活动在温馨的合影留念中缓缓落幕。大家纷纷表示，这次新春轰趴不仅缓解了日常科研的压力，更让大家感受到了课题组这个大家庭的温暖与活力。新的一年，课题组全体成员将以更饱满的热情、更融洽的氛围投入到科研工作中，以团结之姿、奋进之势，书写新的科研篇章。","page.news.20260128-spring-team-building.coverAlt":"师生分工协作，清洗食材、准备餐食","page.news.20260128-spring-team-building.coverAlt1":"师生欢聚一堂，共享火锅与烤肉","page.news.20260128-spring-team-building.coverAlt2":"狼人杀游戏环节，大家欢声笑语、其乐融融","page.news.20260128-spring-team-building.coverAlt3":"全体师生合影留念，定格温馨瞬间","page.news.20260226-lgx-ne.title":"学术动态 | Nature Energy：课题组合作报道钙钛矿器件光循环稳定性研究","page.news.20260226-lgx-ne.coverAlt":"theme","page.news.20260226-lgx-ne.coverAlt_1":"Fig.1","page.news.20260226-lgx-ne.coverAlt_2":"Fig.2","page.news.20260226-lgx-ne.coverAlt_3":"Fig.3","page.news.20260226-lgx-ne.coverAlt_4":"Fig.4","page.news.20260226-lgx-ne.p1":"近日，东南大学材料学院李桂香教授与合作团队在钙钛矿光伏器件户外运行稳定性方面取得重要进展，相关研究成果以“Photoswitchable isomers to improve grain boundary resilience and perovskite solar cells stability under light cycling”为题，发表于国际顶级能源期刊《Nature Energy》（《自然-能源》）。","page.news.20260226-lgx-ne.p2":"该研究针对钙钛矿太阳能电池在户外光照循环中性能衰减的核心难题，提出了一种基于光响应智能分子的晶界动态韧性调控策略。通过在钙钛矿晶界处引入可逆光异构化分子，实现了对光照循环应力的实时耗散与缺陷抑制，为发展高稳定、耐候性强的钙钛矿光电器件提供了全新的材料设计与器件工程思路。","page.news.20260226-lgx-ne.p3":"东南大学材料学院李桂香教授、河南大学李萌教授、德国亥姆霍兹材料与能源中心Antonio Abate教授、斯图加特大学Michael Saliba教授及厦门大学王露遥副教授为论文通讯作者。东南大学材料学院为论文共同通讯单位。研究工作得到了国家自然科学基金及江苏省基础研究计划等项目资助。","page.news.20260226-lgx-ne.p4":"01 研究背景","page.news.20260226-lgx-ne.p5":"金属卤化物钙钛矿光伏技术虽然已实现较高效率的突破，但在真实户外环境中的长期运行稳定性仍是制约其商业化应用的核心挑战，尤其是面对日夜交替、光照循环条件时。传统稳定性测试多采用恒定光照，难以准确模拟实际户外周期性光照应力所造成的损伤累积效应。","page.news.20260226-lgx-ne.p6":"研究显示，含紫外光的光照循环会持续引发钙钛矿的晶格应力，导致晶界处化学键断裂、发生晶体相变，并加速离子迁移与缺陷生成，从而造成器件性能的快速、不可逆衰减。如何让钙钛矿电池在动态变化的光照环境中保持结构韧性，成为该领域亟待攻克的关键科学问题。","page.news.20260226-lgx-ne.p7":"02 \xa0研究亮点","page.news.20260226-lgx-ne.p8":"针对这一难题，研究团队创新性地提出了一种仿生智能的解决方案：在钙钛矿晶界处引入一种名为 Ca-Abz 的光开关偶氮苯衍生物。Ca-Abz分子能像“智能弹簧”一样，根据光照条件动态改变自身构型，从而主动耗散晶格应力，提升器件在光循环下的耐久性。","page.news.20260226-lgx-ne.p9":"1. 分子层面光响应动态构型","page.news.20260226-lgx-ne.p10":"Ca-Abz分子在黑暗中维持伸展的E式构型，与晶界结构匹配；而在紫外光照射下，它将可逆地转变为弯曲的Z式构型。","page.news.20260226-lgx-ne.p11":"这一可逆的光异构化过程，使分子能够实时响应钙钛矿晶格在光照下的膨胀与收缩变化，动态调节晶界区域的局部应变，从而将破坏性的机械应力转化为可逆的分子构象变化，有效抑制微裂纹和缺陷的生产。","page.news.20260226-lgx-ne.p12":"2. 薄膜兼具钝化与缓冲功能","page.news.20260226-lgx-ne.p13":"锚定与钝化：分子一端的羧基能够锚定在钙钛矿晶界处，与Pb(II)形成稳定配位，有效钝化界面缺陷，抑制非辐射复合。","page.news.20260226-lgx-ne.p14":"动态缓冲：分子另一端的偶氮苯光开关结构则作为应力缓冲的柔性单元，通过构型变换吸收和释放应变能量，保护晶界结构完整性。","page.news.20260226-lgx-ne.p15":"3. 器件效率与稳定性双提升","page.news.20260226-lgx-ne.p16":"高效率：制备的p-i-n型钙钛矿太阳能电池获得了27.2% 的光电转换效率（认证MPPT稳态效率26.7%），其开路电压和填充因子均得到显著提升。","page.news.20260226-lgx-ne.p17":"光循环稳定性：在65\xb0C、含紫外光的模拟日光循环（12小时光照/12小时暗态）下持续运行2000小时后，器件性能保持率超过95%。","page.news.20260226-lgx-ne.p18":"热循环稳定性：在-40\xb0C至+85\xb0C 的宽温域内进行500次快速循环后，性能保持率达95.7%，展现出优异的机械与热循环耐受性。","page.news.20260226-lgx-ne.p19":"图1：光循环下钙钛矿器件与薄膜的衰减特性","page.news.20260226-lgx-ne.p20":"图2：采用光开关异构体调控的薄膜动态韧性","page.news.20260226-lgx-ne.p21":"图3：钙钛矿太阳能电池的载流子特性与光伏性能","page.news.20260226-lgx-ne.p22":"图4：钙钛矿光伏器件的长时老化测试性能","page.news.20260226-lgx-ne.p23":"03 论文信息","page.news.20260226-lgx-ne.p24":"论文题目：Photoswitchable isomers to improve grain boundary resilience and perovskite solar cells stability under light cycling","page.news.20260226-lgx-ne.p25":"发表期刊：Nature Energy","page.news.20260226-lgx-ne.p26":"通讯作者：李桂香教授（东南大学）、王露遥副教授（厦门大学）、Michael Saliba教授（斯图加特大学）、Antonio Abate教授（亥姆霍兹材料与能源中心）、李萌教授（河南大学）","page.news.20260226-lgx-ne.doiDesc":"论文链接：","page.news.20260319-wsq-csr.title":"学术动态 | 课题组王少强在《科学通报》期刊发表综述论文","page.news.20260319-wsq-csr.coverAlt":"theme","page.news.20260319-wsq-csr.coverAlt_1":"Fig.1","page.news.20260319-wsq-csr.coverAlt_2":"Fig.2","page.news.20260319-wsq-csr.coverAlt_3":"Fig.3","page.news.20260319-wsq-csr.coverAlt_4":"Fig.4","page.news.20260319-wsq-csr.p1":"近日，东南大学材料学院李桂香教授团队在《科学通报》期刊上发表了题为《人工智能助力杂化半导体光伏结构设计与稳定性提升》（AI-Aided Structural Design and Stability of Hybrid Semiconductor Photovoltaics）的综述文章。","page.news.20260319-wsq-csr.p2":"该论文详细回顾了人工智能（AI）在钙钛矿太阳能电池稳定性优化中的应用进展，重点讨论了AI技术如何在材料筛选、缺陷调控和界面工程等方面推动钙钛矿太阳能电池的高效稳定性提升，为该领域的研究人员提供了新的视角和参考。","page.news.20260319-wsq-csr.p3":"课题组博士生王少强为论文的第一作者，东南大学李桂香教授、邸世民教授，美国圣母大学曹青博士为通讯作者，东南大学材料学院为该论文的第一单位，该工作得到了国家自然科学基金及江苏省基础研究计划项目的资助。","page.news.20260319-wsq-csr.p4":"01 研究背景","page.news.20260319-wsq-csr.p5":"钙钛矿太阳能电池因其高光电转换效率与低成本制造潜力成为新一代光伏技术的重要候选人。然而，其长期稳定性问题仍是制约其商业化应用的关键瓶颈。近年来，人工智能技术在材料科学领域快速发展，逐渐展现出在稳定性调控中的独特优势。","page.news.20260319-wsq-csr.p6":"在此背景下，本文围绕人工智能在钙钛矿太阳能电池稳定性优化中的应用进展，系统梳理了其在材料组分筛选、界面工程设计和缺陷调控方面的典型应用路径与代表性成果。通过引入机器学习(machine learning, ML)、贝叶斯优化(Bayesian optimization, BO)等前沿算法以及AI与密度泛函理论(density functional theory, DFT)和分子动力学(molecular dynamics, MD)结合在复杂多变量体系中的建模能力与应用局限，展望了未来AI与实验闭环结合、多尺度协同建模、数据共享标准化等发展趋势。","page.news.20260319-wsq-csr.p7":"本文旨在为钙钛矿太阳能电池结构稳定性设计提供系统性参考，并推动AI技术在新型光伏器件可靠性提升中的更深层次融合。","page.news.20260319-wsq-csr.p8":"02 \xa0研究内容与亮点","page.news.20260319-wsq-csr.p9":"文章系统总结了人工智能在钙钛矿太阳能电池稳定性优化中的应用，涵盖了多个关键领域：","page.news.20260319-wsq-csr.p10":"1. 材料组分筛选","page.news.20260319-wsq-csr.p11":"通过机器学习，能够预测并筛选出具有最佳稳定性的钙钛矿材料组合，降低了传统实验方法的时间和成本；","page.news.20260319-wsq-csr.p12":"2. 界面工程","page.news.20260319-wsq-csr.p13":"AI帮助优化钙钛矿与其他功能层（如空穴传输层、电子传输层）之间的能级匹配，显著提升了电池的效率与稳定性；","page.news.20260319-wsq-csr.p14":"3. 缺陷调控","page.news.20260319-wsq-csr.p15":"通过大数据分析与模型预测，AI能够识别钙钛矿材料中的缺陷并提出修复策略，从而提升器件性能并延长使用寿命。","page.news.20260319-wsq-csr.p16":"图1：钙钛矿太阳能电池稳定性影响因素.\xa0(a) 理想ABX3钙钛矿的电子结构；(b) 氧气使得Sn2+氧化成Sn4+；(c) 混合比例不均引起相分离；(d) 太阳能电池内载流子的界面复合过程；(e)钙钛矿太阳能电池在持续紫外光照射下的两阶段降解过程；(f) 基于纳米NC-PEDOT:PSS与PEDOT:PSS结构的钙钛矿层应力缓解方案。","page.news.20260319-wsq-csr.p17":"图2：AI在材料的组分筛选方面调控钙钛矿太阳能电池的稳定性：ML与DFT结合预测新型钙钛矿框架示意图。","page.news.20260319-wsq-csr.p18":"图3：AI在材料的组成优化方面调控钙钛矿太阳能电池的稳定性.\xa0(a) 以相分离吉布斯自由能为目标属性的神经网络预测卤化物钙钛矿相图; (b) 预测相图中带隙为1.7与1.8 eV的钙钛矿(分布)；(c) 预测的最优1.7 eV钙钛矿(成分)；(d) 非负矩阵分解ML分析图。","page.news.20260319-wsq-csr.p19":"图4：AI在界面工程与缺陷调控方面调控钙钛矿太阳能电池的稳定性.\xa0(a) 钙钛矿太阳能电池中界面电荷传输的示意图；(b) RF模型在训练集与测试集上的预测值与真实值对比；(c) 通过RF回归算法与SHAP分析得到的电流-电压(I-V)特性的SHAP摘要图；(d) 9种MAPbX3化合物的主导杂质筛选结果；(e) 当PH阴离子在VI位发生取代时，IPb反位缺陷的缺陷形成能(ΔEf)；(f) ML预测值与实际空穴迁移率的散点图。","page.news.20260319-wsq-csr.p20":"03 研究意义","page.news.20260319-wsq-csr.p21":"通过AI技术的引入，钙钛矿太阳能电池的研究进入了一个新的时代。这些技术不仅能加速材料的筛选与优化，还能为界面层设计、缺陷修复等方面提供理论支持，极大提高了钙钛矿电池的长期稳定性，推动了其实际应用。","page.news.20260319-wsq-csr.p22":"04 论文信息","page.news.20260319-wsq-csr.p23":"论文标题：人工智能助力杂化半导体光伏结构设计与稳定性提升","page.news.20260319-wsq-csr.p24":"发表期刊：《科学通报》","page.news.20260319-wsq-csr.p25":"通讯作者：李桂香教授（东南大学）、邸世民教授（东南大学）、曹青博士（美国圣母大学）","page.news.20260319-wsq-csr.doiDesc":"论文链接："}')}}]);